"use client";

import { useState } from "react";
import SectionContainer from "@/components/home/SectionContainer";

const questions = [
  {
    question: "Kunnen wij CoachScribe gebruiken binnen een AVG-werkwijze?",
    answer:
      "CoachScribe ondersteunt een AVG-werkwijze met duidelijke rollen, versleuteling, verwerkersdocumentatie en verwijdermogelijkheden. Jij blijft als coach verwerkingsverantwoordelijke voor de inhoud die je verwerkt.",
  },
  {
    question: "Blijven patiënt- en sessiegegevens binnen de EU?",
    answer:
      "Patiënt- en sessie-inhoud wordt verwerkt en opgeslagen binnen de EU-regio's die wij voor CoachScribe gebruiken. Voor sommige account- of abonnementsfuncties kan beperkte metadata via externe partijen lopen.",
  },
  {
    question: "Worden onze gegevens gebruikt om publieke AI-modellen te trainen?",
    answer:
      "Nee. Inhoud uit CoachScribe wordt niet door ons gebruikt om publieke AI-modellen te trainen.",
  },
  {
    question: "Hoe ziet de beveiliging in de praktijk eruit?",
    answer:
      "We gebruiken onder meer versleutelde verzending, versleutelde opslag, toegangsbeperking, tijdelijke uploadrechten voor transcriptie en misbruikdetectie via rate limiting.",
  },
  {
    question: "Welke documentatie is beschikbaar voor grotere organisaties?",
    answer:
      "Op aanvraag delen wij relevante documentatie zoals de verwerkersovereenkomst en subverwerkerinformatie. Hiermee kunnen privacy officers en inkopers sneller toetsen.",
  },
  {
    question: "Kan ik gegevens verwijderen als een cliënt daarom vraagt?",
    answer:
      "Ja. Je kunt sessiegegevens verwijderen binnen CoachScribe. Bij beëindiging van een account verwijderen wij bijbehorende gegevens volgens het geldende beleid en wettelijke vereisten.",
  },
  {
    question: "Wat als onze organisatie aanvullende security-eisen heeft?",
    answer:
      "Neem contact op met ons team. We bespreken dan de vereisten, beschikbare documentatie en het implementatiepad dat past bij jullie governance-eisen.",
  },
];

export default function VeiligheidFaqSection() {
  const [expandedQuestion, setExpandedQuestion] = useState<string | null>(null);

  return (
    <SectionContainer className="bg-[#F8F9F9]" contentClassName="md:pt-10 md:pb-20">
      <div id="faq" className="flex w-full flex-col gap-8">
        <h2 className="text-4xl font-semibold text-[#1D0A00] md:text-6xl">
          Veelgestelde vragen
        </h2>
        <div className="w-full border-y border-black/40">
          {questions.map((questionItem, index) => {
            const isExpanded = expandedQuestion === questionItem.question;
            return (
              <div
                key={questionItem.question}
                className={index === 0 ? "" : "border-t border-black/40"}
              >
                <button
                  type="button"
                  aria-expanded={isExpanded}
                  aria-controls={`faq-answer-${index}`}
                  onClick={() =>
                    setExpandedQuestion((previousQuestion) =>
                      previousQuestion === questionItem.question
                        ? null
                        : questionItem.question,
                    )
                  }
                  className="flex w-full cursor-pointer items-center justify-between gap-6 py-5 text-left text-[#1D0A00] transition-colors hover:text-[#BD0265]"
                >
                  <span className="text-base font-semibold md:text-xl">
                    {questionItem.question}
                  </span>
                  <span
                    aria-hidden="true"
                    className={`shrink-0 transition-transform duration-[700ms] ease-[cubic-bezier(0.22,1,0.36,1)] ${
                      isExpanded ? "rotate-45" : ""
                    }`}
                  >
                    <svg
                      xmlns="http://www.w3.org/2000/svg"
                      width="24"
                      height="24"
                      viewBox="0 0 24 24"
                      fill="none"
                    >
                      <path
                        d="M6 12H18"
                        stroke="#1D0A00"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                      <path
                        d="M12 18V6"
                        stroke="#1D0A00"
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    </svg>
                  </span>
                </button>
                <div
                  id={`faq-answer-${index}`}
                  className="grid overflow-hidden transition-[grid-template-rows,opacity] duration-[700ms] ease-[cubic-bezier(0.22,1,0.36,1)]"
                  style={{
                    gridTemplateRows: isExpanded ? "1fr" : "0fr",
                    opacity: isExpanded ? 1 : 0,
                  }}
                >
                  <p className="overflow-hidden pb-5 text-base font-normal leading-relaxed text-[#1D0A00]">
                    {questionItem.answer}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </SectionContainer>
  );
}
